class MyMeta(type):
    def __new__(cls, name, bases, dct):
        print(f"Creating class {name} with MyMeta metaclass")
        # Optionally add or modify class attributes
        dct['created_by_meta'] = True
        return super().__new__(cls, name, bases, dct)


class MyClass(metaclass=MyMeta):
    pass

print(MyClass.created_by_meta)  # Output: True

class RegistryMeta(type):
    registry = {}

    def __new__(cls, name, bases, dct):
        new_cls = super().__new__(cls, name, bases, dct)
        if name != 'Base':  # Avoid registering base class itself
            cls.registry[name] = new_cls
        return new_cls


class Base(metaclass=RegistryMeta):
    pass


class PluginA(Base):
    pass


class PluginB(Base):
    pass

print(RegistryMeta.registry)  # {'PluginA': <class '__main__.PluginA'>, 'PluginB': <class '__main__.PluginB'>}

class SafeResource:
    def __enter__(self):
        print('Resource acquired')
        return self

    def __exit__(self, exc_type, exc_value, traceback):
        try:
            print('Cleaning up resource')
            # Simulated cleanup that raises an error
            raise RuntimeError('Cleanup failed!')
        except Exception as cleanup_error:
            print(f'Error during cleanup: {cleanup_error}')
            # Suppress the cleanup error to not override original exceptions
            # Return False if you want the cleanup error to propagate
        # Returning False lets exceptions from the with block propagate
        return False

# Using the context manager
try:
    with SafeResource() as res:
        print('Doing work with resource')
        raise ValueError('Oops! Something went wrong')
except Exception as e:
    print(f'Caught exception: {e}')

from contextlib import contextmanager

@contextmanager
def safe_resource():
    print('Resource acquired')
    try:
        yield
    finally:
        try:
            print('Cleaning up resource')
            raise RuntimeError('Cleanup failed!')
        except Exception as cleanup_error:
            print(f'Error during cleanup: {cleanup_error}')


try:
    with safe_resource():
        print('Doing work with resource')
        raise ValueError('Oops! Something went wrong')
except Exception as e:
    print(f'Caught exception: {e}')

